/**
 * gh-vehicle-duty — single-file HTTP API for Cloudflare Workers.
 *
 * BUNDLED BUILD: library + API in one file, so it can be pasted directly into
 * the Cloudflare dashboard editor (no CLI, no npm, no build step).
 *
 * Source of truth is the repo: src/duty.js + api/worker.js.
 * Do not edit this file by hand — regenerate it with `npm run api:bundle`.
 *
 * @license MIT
 */

/* ===== library (src/duty.js) ===== */

/**
 * gh-vehicle-duty — Ghana vehicle import duty & levy calculator.
 *
 * ESTIMATE ONLY. This library reproduces the arithmetic of a GRA Customs
 * Bill of Entry. It does NOT know GRA's official customs value: that is
 * assessed from the vehicle's VIN against GRA's ICUMS/HDV benchmark
 * database, which has no public API. Callers supply the value; this library
 * applies the levy schedule to it. Always confirm with a licensed clearing
 * agent before relying on a figure.
 *
 * @license MIT
 */

/* ------------------------------------------------------------------ *
 * Rate schedule — VERSIONED.
 *
 * Ghana's levy schedule changes with each budget. The Jan 2026 VAT reform,
 * for example, removed the 1% COVID-19 Health Recovery Levy. Consumers of
 * this library MUST check `RATES.version` / `RATES.validFrom` rather than
 * assuming these numbers are current.
 * ------------------------------------------------------------------ */

const RATES = Object.freeze({
  version: "2026.1",
  validFrom: "2026-01-01",
  source: "Validated against a GRA Customs Bill of Entry (post-Jan-2026 VAT reform).",
  currency: "GHS",

  /** Levies charged on the customs value (CIF in GHS). */
  onCustomsValue: Object.freeze([
    Object.freeze({ code: "06", name: "ECOWAS Levy (ETLS)", rate: 0.005 }),
    Object.freeze({ code: "31", name: "Vehicle Examination Fee", rate: 0.01 }),
    Object.freeze({ code: "78", name: "Special Import Levy", rate: 0.02 }),
    Object.freeze({ code: "87", name: "EXIM Bank Levy", rate: 0.0075 }),
    Object.freeze({ code: "98", name: "African Union Import Levy", rate: 0.002 }),
  ]),

  /** Levies charged on the VAT base (customs value + import duty). */
  onVatBase: Object.freeze([
    Object.freeze({ code: "02", name: "Import VAT", rate: 0.15 }),
    Object.freeze({ code: "47", name: "Import NHIL", rate: 0.025 }),
    Object.freeze({ code: "88", name: "GET Fund Levy", rate: 0.025 }),
  ]),

  /** Network charge is assessed on FOB, not the full customs value. */
  networkCharge: Object.freeze({ code: "32", name: "Network Charge", rate: 0.004 }),

  /** Sub-levies charged on the network charge itself. */
  onNetworkCharge: Object.freeze([
    Object.freeze({ code: "33", name: "Network Charge VAT", rate: 0.15 }),
    Object.freeze({ code: "48", name: "Network Charge NHIL", rate: 0.025 }),
    Object.freeze({ code: "89", name: "Network Charge GET Fund", rate: 0.025 }),
  ]),

  /** Flat fees in GHS. */
  fixedFees: Object.freeze([
    Object.freeze({ code: "45", name: "Ghana Shippers Authority SNF", amount: 12.0 }),
    Object.freeze({ code: "63", name: "GHS Disinfection Fee", amount: 410.76 }),
  ]),

  /** Optional processing fee (code 05); often assessed at 0. */
  processingFee: Object.freeze({ code: "05", name: "Processing Fee", rate: 0.01 }),

  /** Common import duty rates by vehicle class. Actual rate follows HS classification. */
  dutyRates: Object.freeze({ passenger: 0.2, pickup: 0.1, commercial: 0.1, reduced: 0.05 }),
});

/* ------------------------------------------------------------------ *
 * HS classification helpers
 * ------------------------------------------------------------------ */

const PICKUP_HINTS = ["pickup", "truck", "cab chassis"];

/** True if the body type reads as a pickup/commercial vehicle. */
function isPickup(bodyType) {
  const b = String(bodyType || "").toLowerCase();
  return PICKUP_HINTS.some((h) => b.includes(h));
}

/** Suggested import duty rate for a body type. Override per your HS code. */
function dutyRateForBody(bodyType) {
  return isPickup(bodyType) ? RATES.dutyRates.pickup : RATES.dutyRates.passenger;
}

/**
 * HS subheading for a petrol passenger car by engine displacement (cc).
 * Pickups/commercial vehicles fall under 8704 instead.
 */
function hsCode(engineCC, bodyType) {
  if (isPickup(bodyType)) return "8704";
  const cc = Number(engineCC);
  if (!cc || !isFinite(cc)) return "8703";
  if (cc <= 1000) return "8703.21";
  if (cc <= 1500) return "8703.22";
  if (cc <= 3000) return "8703.23";
  return "8703.24";
}

/* ------------------------------------------------------------------ *
 * Value helpers
 * ------------------------------------------------------------------ */

/**
 * Convert an invoice (FOB/freight/insurance in foreign currency) into the
 * GHS figures the levy engine needs.
 *
 * @param {object} o
 * @param {number} o.fob             FOB / purchase price, foreign currency
 * @param {number} [o.freight=0]     Freight, foreign currency
 * @param {number} [o.insurance=0]   Insurance, foreign currency
 * @param {number} o.exchangeRate    Units of GHS per 1 unit foreign currency
 * @param {number} [o.depreciation=0] Fraction (0–1) applied to the goods value for used vehicles
 * @returns {{customsValue:number, fobGhs:number}} both in GHS
 */
function customsValueFromInvoice({
  fob,
  freight = 0,
  insurance = 0,
  exchangeRate,
  depreciation = 0,
}) {
  if (!isFinite(fob) || fob < 0) throw new TypeError("fob must be a non-negative number");
  if (!isFinite(exchangeRate) || exchangeRate <= 0)
    throw new TypeError("exchangeRate must be a positive number");
  if (depreciation < 0 || depreciation >= 1)
    throw new RangeError("depreciation must be a fraction in [0, 1)");

  const effectiveFob = fob * (1 - depreciation);
  return {
    fobGhs: effectiveFob * exchangeRate,
    customsValue: (effectiveFob + freight + insurance) * exchangeRate,
  };
}

/* ------------------------------------------------------------------ *
 * Core calculation
 * ------------------------------------------------------------------ */

/**
 * Calculate the full duty & levy breakdown.
 *
 * @param {object} o
 * @param {number} o.customsValue        CIF in GHS. The figure GRA assesses.
 * @param {number} [o.fobGhs]            FOB in GHS (network-charge base). Defaults to customsValue.
 * @param {number} [o.dutyRate=0.20]     Import duty rate as a fraction.
 * @param {boolean} [o.processingFee=false] Apply the 1% processing fee.
 * @param {boolean} [o.includeFixedFees=true] Include flat fees (SNF, disinfection).
 * @param {object} [o.rates=RATES]       Override the rate schedule.
 * @returns {object} breakdown with `lines`, `total`, `effectiveRate`, `ratesVersion`
 */
function calculateDuty({
  customsValue,
  fobGhs,
  dutyRate = RATES.dutyRates.passenger,
  processingFee = false,
  includeFixedFees = true,
  rates = RATES,
} = {}) {
  if (!isFinite(customsValue) || customsValue < 0)
    throw new TypeError("customsValue must be a non-negative number");
  if (!isFinite(dutyRate) || dutyRate < 0 || dutyRate > 1)
    throw new RangeError("dutyRate must be a fraction in [0, 1]");

  const fob = isFinite(fobGhs) && fobGhs >= 0 ? fobGhs : customsValue;
  const lines = [];

  // 1. Import duty — on customs value.
  const duty = customsValue * dutyRate;
  lines.push({
    code: "01", name: "Import Duty", base: "customsValue",
    baseAmount: customsValue, rate: dutyRate, amount: duty,
  });

  // 2. Optional processing fee — on customs value.
  if (processingFee) {
    lines.push({
      code: rates.processingFee.code, name: rates.processingFee.name, base: "customsValue",
      baseAmount: customsValue, rate: rates.processingFee.rate,
      amount: customsValue * rates.processingFee.rate,
    });
  }

  // 3. Levies on customs value.
  for (const l of rates.onCustomsValue) {
    lines.push({
      code: l.code, name: l.name, base: "customsValue",
      baseAmount: customsValue, rate: l.rate, amount: customsValue * l.rate,
    });
  }

  // 4. VAT block — base is customs value PLUS import duty.
  const vatBase = customsValue + duty;
  for (const l of rates.onVatBase) {
    lines.push({
      code: l.code, name: l.name, base: "vatBase",
      baseAmount: vatBase, rate: l.rate, amount: vatBase * l.rate,
    });
  }

  // 5. Network charge — on FOB — and its sub-levies.
  const nc = fob * rates.networkCharge.rate;
  lines.push({
    code: rates.networkCharge.code, name: rates.networkCharge.name, base: "fob",
    baseAmount: fob, rate: rates.networkCharge.rate, amount: nc,
  });
  for (const l of rates.onNetworkCharge) {
    lines.push({
      code: l.code, name: l.name, base: "networkCharge",
      baseAmount: nc, rate: l.rate, amount: nc * l.rate,
    });
  }

  // 6. Flat fees.
  if (includeFixedFees) {
    for (const fee of rates.fixedFees) {
      lines.push({
        code: fee.code, name: fee.name, base: "fixed",
        baseAmount: null, rate: null, amount: fee.amount,
      });
    }
  }

  const total = lines.reduce((sum, l) => sum + l.amount, 0);

  return {
    customsValue,
    fobGhs: fob,
    vatBase,
    importDuty: duty,
    lines,
    total,
    effectiveRate: customsValue > 0 ? total / customsValue : 0,
    currency: rates.currency,
    ratesVersion: rates.version,
    validFrom: rates.validFrom,
    disclaimer:
      "Estimate only. GRA assesses the official customs value from the vehicle VIN " +
      "against its ICUMS/HDV benchmark. Confirm with a licensed clearing agent.",
  };
}

/** Convenience: invoice figures straight to a breakdown. */
function calculateFromInvoice(opts = {}) {
  const { customsValue, fobGhs } = customsValueFromInvoice(opts);
  return calculateDuty({ ...opts, customsValue, fobGhs });
}

/** Format a number as GHS for display. */
function formatGHS(n) {
  return new Intl.NumberFormat("en-GH", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(isFinite(n) ? n : 0);
}

/* ===== API (api/worker.js) ===== */

/**
 * gh-vehicle-duty — HTTP API (Cloudflare Worker)
 *
 * A thin wrapper over ../src/duty.js. Pure arithmetic: no database, no auth,
 * no user data stored.
 *
 * Endpoints:
 *   GET  /            → service info + rate schedule version
 *   GET  /rates       → the full levy schedule with freshness status
 *   GET  /health      → uptime + staleness check
 *   POST /calculate   → duty breakdown
 *   GET  /calculate?customsValue=750093&dutyRate=0.2  (convenience)
 *
 * Every response carries `ratesVersion`, `validFrom` and a `staleness` block
 * so callers can detect an out-of-date deployment. See STALENESS_* below.
 *
 * @license MIT
 */

/* ------------------------------------------------------------------ *
 * Staleness policy
 *
 * Ghana's levy schedule changes with each budget (typically November,
 * effective January). An API is riskier than a library here: library users
 * are pinned to the version they installed, but every API caller instantly
 * inherits whatever this deployment happens to be running. If this Worker
 * is not redeployed after a budget change, callers silently receive wrong
 * numbers with no way to tell.
 *
 * So: every response self-reports its age, and past a threshold the API
 * degrades loudly rather than quietly.
 * ------------------------------------------------------------------ */
const STALENESS_WARN_DAYS = 365;   // ~1 budget cycle → warn
const STALENESS_ERROR_DAYS = 550;  // ~1.5 cycles → flag as unreliable

function staleness() {
  const validFrom = new Date(RATES.validFrom + "T00:00:00Z");
  const ageDays = Math.floor((Date.now() - validFrom.getTime()) / 86400000);
  let level = "current";
  let message = "Rate schedule is current.";
  if (ageDays >= STALENESS_ERROR_DAYS) {
    level = "stale";
    message =
      `Rate schedule is ${ageDays} days old and has likely been superseded by at ` +
      `least one budget. Do NOT rely on these figures. Verify against a current ` +
      `GRA Bill of Entry before use.`;
  } else if (ageDays >= STALENESS_WARN_DAYS) {
    level = "aging";
    message =
      `Rate schedule is ${ageDays} days old. Ghana's levies change with each ` +
      `budget — confirm these rates are still in force.`;
  }
  return { level, ageDays, validFrom: RATES.validFrom, version: RATES.version, message };
}

const DISCLAIMER =
  "Estimate only. This API applies a levy schedule to a customs value you supply. " +
  "It does not know GRA's official valuation, which is assessed from the vehicle VIN " +
  "against GRA's ICUMS/HDV benchmark. Not affiliated with the Ghana Revenue Authority. " +
  "Confirm with a licensed clearing agent before making financial or clearing decisions.";

const CORS = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type",
  "Access-Control-Max-Age": "86400",
};

function json(body, status = 200, extraHeaders = {}) {
  const s = staleness();
  return new Response(JSON.stringify(body, null, 2), {
    status,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      "Cache-Control": "public, max-age=300",
      // Surfaced as headers too, so callers can check without parsing the body.
      "X-Rates-Version": RATES.version,
      "X-Rates-Valid-From": RATES.validFrom,
      "X-Rates-Staleness": s.level,
      ...CORS,
      ...extraHeaders,
    },
  });
}

function fail(message, status = 400, extra = {}) {
  return json({ error: true, message, ...extra }, status);
}

/** Coerce a query/body value to a finite number, or undefined. */
function toNum(v) {
  if (v === undefined || v === null || v === "") return undefined;
  const n = typeof v === "number" ? v : parseFloat(v);
  return isFinite(n) ? n : NaN;
}

/** Shared handler for GET and POST /calculate. */
function handleCalculate(input) {
  const customsValue = toNum(input.customsValue);
  const fob = toNum(input.fob);

  if (customsValue === undefined && fob === undefined) {
    return fail(
      "Provide either `customsValue` (CIF in GHS) or `fob` plus `exchangeRate`.",
      400,
      {
        examples: {
          byCustomsValue: { customsValue: 750093, dutyRate: 0.2 },
          byInvoice: { fob: 62400, freight: 960, exchangeRate: 11.7359, dutyRate: 0.2 },
        },
      }
    );
  }

  const dutyRate = toNum(input.dutyRate);
  const bodyType = input.bodyType;
  const engineCC = toNum(input.engineCC);

  // Resolve duty rate: explicit > derived from body type > passenger default.
  let rate = dutyRate;
  if (rate === undefined) rate = bodyType ? dutyRateForBody(bodyType) : RATES.dutyRates.passenger;

  try {
    let result;
    if (customsValue !== undefined) {
      result = calculateDuty({
        customsValue,
        fobGhs: toNum(input.fobGhs),
        dutyRate: rate,
        processingFee: input.processingFee === true || input.processingFee === "true",
        includeFixedFees: !(input.includeFixedFees === false || input.includeFixedFees === "false"),
      });
    } else {
      const exchangeRate = toNum(input.exchangeRate);
      if (exchangeRate === undefined)
        return fail("`exchangeRate` is required when calculating from `fob`.");
      result = calculateFromInvoice({
        fob,
        freight: toNum(input.freight) || 0,
        insurance: toNum(input.insurance) ?? fob * 0.01, // ~1% of value if omitted
        exchangeRate,
        depreciation: toNum(input.depreciation) || 0,
        dutyRate: rate,
        processingFee: input.processingFee === true || input.processingFee === "true",
      });
    }

    if (bodyType || engineCC) {
      result.classification = {
        bodyType: bodyType ?? null,
        engineCC: engineCC ?? null,
        hsCode: hsCode(engineCC, bodyType),
        suggestedDutyRate: bodyType ? dutyRateForBody(bodyType) : null,
      };
    }

    result.staleness = staleness();
    return json(result);
  } catch (err) {
    // Library throws TypeError/RangeError on bad input — surface as 400.
    if (err instanceof TypeError || err instanceof RangeError) return fail(err.message, 400);
    return fail("Calculation failed.", 500);
  }
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname.replace(/\/+$/, "") || "/";

    if (request.method === "OPTIONS") return new Response(null, { status: 204, headers: CORS });

    if (path === "/health") {
      const s = staleness();
      return json(
        { ok: s.level !== "stale", status: s.level, staleness: s },
        s.level === "stale" ? 503 : 200
      );
    }

    if (path === "/rates") {
      return json({ ...RATES, staleness: staleness(), disclaimer: DISCLAIMER });
    }

    if (path === "/calculate") {
      if (request.method === "GET") {
        return handleCalculate(Object.fromEntries(url.searchParams));
      }
      if (request.method === "POST") {
        let body;
        try {
          body = await request.json();
        } catch {
          return fail("Request body must be valid JSON.");
        }
        if (typeof body !== "object" || body === null) return fail("Request body must be a JSON object.");
        return handleCalculate(body);
      }
      return fail("Use GET or POST.", 405);
    }

    if (path === "/") {
      return json({
        name: "gh-vehicle-duty API",
        description: "Ghana vehicle import duty & levy estimates.",
        ratesVersion: RATES.version,
        validFrom: RATES.validFrom,
        staleness: staleness(),
        endpoints: {
          "GET /": "This message.",
          "GET /rates": "Full levy schedule.",
          "GET /health": "Uptime and rate-freshness check.",
          "POST /calculate": "Duty breakdown. JSON body.",
          "GET /calculate?customsValue=750093&dutyRate=0.2": "Duty breakdown via query string.",
        },
        parameters: {
          customsValue: "number (GHS) — CIF. Either this or `fob`+`exchangeRate`.",
          fob: "number — price in foreign currency.",
          freight: "number — optional.",
          insurance: "number — optional; defaults to ~1% of fob.",
          exchangeRate: "number — GHS per unit foreign currency.",
          depreciation: "number 0–1 — used-vehicle valuation haircut.",
          dutyRate: "number 0–1 — defaults to 0.20, or derived from bodyType.",
          bodyType: "string — e.g. 'SUV', 'Pickup'. Sets duty rate and HS code.",
          engineCC: "number — engine displacement, for HS classification.",
          processingFee: "boolean — apply the 1% processing fee.",
        },
        source: "https://github.com/YOUR-USERNAME/gh-vehicle-duty",
        disclaimer: DISCLAIMER,
      });
    }

    return fail(`Unknown endpoint: ${path}`, 404);
  },
};
